import{_ as t,o as e,c as n,O as i}from"./chunks/framework.92cbe775.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/pitch.md","filePath":"en/materials/pitch.md","lastUpdated":1776068451000}'),s={name:"en/materials/pitch.md"};function r(l,a,d,o,p,c){return e(),n("div",null,a[0]||(a[0]=[i('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Pitch Outline</p><h1>Pitch</h1><div class="brand-hero__panel"><span class="brand-pill">Talking Point</span><strong>The most effective introduction does not start by piling on technical terms. It starts by judging whether the other side is currently in the free path, local script-slot expansion, formal team collaboration, or enterprise delivery.</strong><p>Get the entry path right first, then explain platform position, problem definition, and delivery style. That keeps personal expansion, the standard team edition, and enterprise delivery from collapsing into one vague story.</p></div><p class="brand-lead"> This page concentrates the core way to introduce ExecGov, covering platform position, problem definition, the four-layer path, and the current landing focus. It works well for first contact, the opening of an introduction, and alignment before more formal communication. </p><div class="brand-chip-list"><span class="brand-chip">30-second version</span><span class="brand-chip">3-minute version</span><span class="brand-chip">Compact structure</span><span class="brand-chip">Conversation-ready</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./value.html">View the Value Framing</a><a class="cta-button" href="../product/index.html">View Product Overview</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // PITCH OUTLINE</span><span>MAT 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">problem</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">scripts_exist</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">entry_is_fragmented</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">platform</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">intent_routing</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">controlled_execution</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">path</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">free</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">local_slots</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">team_saas</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">private_delivery</span></span></div><div class="matrix-panel__callout">GOOD PITCHES REDUCE CONFUSION FAST</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">30s</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">3min</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">format</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">deck</span></span></div></div></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">30 Seconds</p><h2>How to explain it in 30 seconds</h2><p>ExecGov is not another chat shell for a team. It helps you bring scattered and risky scripts under control. You can review who executed what, when it happened, and what the result was, and high-risk actions require confirmation first. The first mature capability carrier already in place today is the Python script.</p></article><article class="brand-card"><p class="brand-kicker">3 Minutes</p><h2>How to explain it in 3 minutes</h2><p>Start with the problem: many teams already have scripts, interfaces, and workflows, but they are scattered across shared drives, servers, and personal machines, which makes execution risky and handover expensive. Then explain the platform: AI handles request understanding and capability recommendation, while the platform handles boundary control, confirmation, execution, and audit. Finally explain the path: individuals start from the free path, people who keep using scripts but are still not in formal collaboration can expand local script slots, teams entering multi-user collaboration move into the formal monthly or annual team-tenant path, and customers who need stronger isolation, intranet deployment, or formal project acceptance move into enterprise delivery. Right now the important thing is solving the real problem well, not telling an overly distant roadmap story.</p></article></section><section class="brand-card"><p class="brand-kicker">Entry First</p><h2>Judge which layer the other side is in first, then decide how to explain it</h2><table><thead><tr><th>Current audience</th><th>What to lead with</th><th>What not to say first</th><th>Suggested entry</th></tr></thead><tbody><tr><td>People touching the platform for the first time</td><td>Lead with the platform position, the pain point, and the value of the free experience</td><td>Do not start with enterprise delivery or heavy customization</td><td><a href="../guide/getting-started.html">Getting Started</a></td></tr><tr><td>People already using scripts continuously in their personal space</td><td>Lead with local script-slot expansion and lightweight paid add-ons</td><td>Do not present personal expansion as the formal team edition</td><td><a href="./membership-benefits-pricing.html">Membership and Pricing</a></td></tr><tr><td>Teams preparing for multi-user collaboration</td><td>Lead with the formal monthly or annual team-tenant path</td><td>Do not frame the shared-SaaS route as if private deployment is the default</td><td><a href="../product/personal-billing-membership.html">Billing and Membership</a></td></tr><tr><td>Customers who need stronger isolation, intranet deployment, or formal project acceptance</td><td>Lead with deployment, delivery boundaries, and the enterprise project rhythm</td><td>Do not keep using the standard membership-page narrative</td><td><a href="../product/deployment.html">Deployment</a> / <a href="./service-packages.html">Kickoff Options / Service Packages</a></td></tr></tbody></table></section><section class="brand-card"><p class="brand-kicker">Deck Structure</p><h2>How a short introduction deck can be structured</h2><table><thead><tr><th>Slide</th><th>Title</th><th>What this slide should make clear</th><th>Suggested visual</th></tr></thead><tbody><tr><td>01</td><td>Cover</td><td>State the platform name and the one-line position clearly</td><td>Main visual plus slogan</td></tr><tr><td>02</td><td>What problem are we solving</td><td>Many companies already have scripts, interfaces, and workflows, but no unified execution entry</td><td>Scattered scripts converging into one platform entry</td></tr><tr><td>03</td><td>What is the platform</td><td>It is not a generic chat system. It is a trusted execution platform.</td><td>A layered diagram showing the conversation layer above capabilities and permissions</td></tr><tr><td>04</td><td>Core delivery modes</td><td>Standard shared-SaaS tenants and enterprise single-tenant delivery are the two real current paths</td><td>A dual-path visual for shared SaaS and enterprise delivery</td></tr><tr><td>05</td><td>Why customers pay for it</td><td>Customers are buying efficiency, isolation, and sustainable updates, not just a page</td><td>Manual operation versus platform execution comparison</td></tr><tr><td>06</td><td>Execution loop</td><td>User request to AI understanding to capability recommendation to confirmation to execution to result</td><td>A horizontal flow diagram</td></tr><tr><td>07</td><td>Current landed capabilities</td><td>Multi-tenancy, capability onboarding, the intelligent brain, hot update, and the CLI already have a real base</td><td>A wall of capability cards</td></tr><tr><td>08</td><td>Security and isolation advantages</td><td>The strength is not talking better. It is doing work only inside authorized boundaries.</td><td>A boundary diagram for tenants, permissions, confirmation, and audit</td></tr><tr><td>09</td><td>Current stage and next step</td><td>Stabilize the 1.0 delivery version first, then decide which parts deserve to be standardized into 2.0</td><td>Version roadmap</td></tr><tr><td>10</td><td>Closing slide</td><td>Close with one clear statement of value</td><td>Main visual plus contact information</td></tr></tbody></table></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Do Say</p><h2>Key points to say externally</h2><ul class="brand-list"><li>First judge whether the other side belongs to the free path, local script-slot expansion, the team edition, or enterprise delivery.</li><li>ExecGov brings scattered scripts, interfaces, and workflows into a unified entry point.</li><li>AI recommends and triggers capabilities inside rules.</li><li>The platform emphasizes tenant isolation, confirmation before execution, and audit trails.</li><li>The standard team edition is currently carried by the shared-SaaS frontend, while enterprise projects move into stronger isolation later.</li><li>Explain what is already usable now before talking about later expansion.</li></ul></article><article class="brand-card"><p class="brand-kicker">Current Stage</p><h2>The current stage is better understood this way</h2><ul class="brand-list"><li>The most mature execution asset on the platform today is the Python script.</li><li><code>execgov-cli</code> is suitable for local onboarding and early validation, and the resident Agent capability is still being strengthened.</li><li>Formal customer delivery currently follows two practical paths: a shared-SaaS formal tenant entry and enterprise single-tenant delivery.</li><li>The <code>public</code> super-admin side already has a first HTTP capability-access sample, which verifies how a second capability type can enter the governance chain.</li><li>A more standardized small-team usage pattern will continue to tighten, and the shared-SaaS frontend is currently carried by <code>tenant_1003+</code> / <code>exec-gov-common</code>.</li><li>More capability types will gradually join the unified governance chain.</li></ul></article><article class="brand-card"><p class="brand-kicker">Demo Order</p><h2>Suggested explanation order</h2><ol class="brand-list"><li>First judge whether the other side belongs to the free path, local script-slot expansion, the team edition, or enterprise delivery.</li><li>Then explain the problem and the platform definition.</li><li>Then show the matching experience path or the team-upgrade path.</li><li>Then explain customer flow, delivery, and isolation boundaries.</li><li>Finally add CLI or deployment details only when they are needed.</li></ol></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>The value judgment can continue on the next page</h2><p class="brand-lead">Continue into the value framing page to close the questions that business owners, operators, and delivery leads care about most.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="./value.html"><span>Value</span><strong>Value Framing</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>Customer Flow / Delivery</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>Edition Roadmap</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>Discuss a real scenario</strong></a></div></div></section></div>',1)]))}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
